import { useState, useEffect } from 'react'
import { Box, Button, Checkbox, Group, SegmentedControl, Text, Tooltip } from '@mantine/core'
import { IconAlertTriangle } from '@tabler/icons-react'
import { notifications } from '@mantine/notifications'
import { MergePDFs, SavePDF } from '../../../wailsjs/go/main/App'
import MergeModeThumbnailPanel, { DEFAULT_TOTAL_WIDTH, FirstPageIn, SelectedPage } from './ThumbnailPanel'
import DetailPanel from '../DetailPanel'
import { usePDFFile } from '../../hooks/usePDFFile'
import * as pageCache from '../../hooks/pageCache'

function basename(p: string) {
  return p.split(/[\\/]/).pop() ?? p
}

export default function MergeMode() {
  const fileA = usePDFFile()
  const fileB = usePDFFile()
  const [selectedPage, setSelectedPage] = useState<SelectedPage>({ file: 'a', page: 1 })
  const [firstPageIn, setFirstPageIn] = useState<FirstPageIn>('a')
  const [reverseB, setReverseB] = useState(true)
  const [merging, setMerging] = useState(false)
  const [totalWidth, setTotalWidth] = useState(DEFAULT_TOTAL_WIDTH)

  useEffect(() => {
    return () => {
      if (fileA.path) pageCache.evict(fileA.path)
      if (fileB.path) pageCache.evict(fileB.path)
    }
  }, [fileA.path, fileB.path])

  // Subtract 22px to account for scrollbar + gap
  const colWidth = Math.floor((totalWidth - 22) / 2)

  const handleChoose = async (file: FirstPageIn) => {
    const loaded = await (file === 'a' ? fileA : fileB).load()
    if (loaded) setSelectedPage({ file, page: 1 })
  }

  const handleMerge = async () => {
    if (!fileA.path || !fileB.path) return
    const outPath = await SavePDF()
    if (!outPath) return
    setMerging(true)
    try {
      await MergePDFs(
        fileA.path, fileB.path, outPath,
        firstPageIn === 'a', reverseB,
        [...fileA.skipped], [...fileB.skipped],
        Object.fromEntries(fileA.rotations), Object.fromEntries(fileB.rotations),
      )
      notifications.show({ message: `Saved to ${outPath}`, color: 'green' })
    } catch (e) {
      notifications.show({ title: 'Merge failed', message: String(e), color: 'red' })
    } finally {
      setMerging(false)
    }
  }

  const bothLoaded = fileA.path !== null && fileB.path !== null
  const unequalCounts = bothLoaded && fileA.count !== fileB.count
  const selectedFile = selectedPage.file === 'a' ? fileA : fileB
  const selectedPath = selectedFile.path
  const selectedCount = selectedFile.count

  return (
    <Box style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <Box
        style={{
          flexShrink: 0,
          borderBottom: '1px solid var(--mantine-color-gray-3)',
          display: 'flex',
          alignItems: 'stretch',
        }}
      >
        <FilePickerColumn label="File A" path={fileA.path} width={colWidth} onChoose={() => handleChoose('a')} />
        {/* Add 26 px to account for scrollbar + gap */}
        <FilePickerColumn label="File B" path={fileB.path} width={colWidth + 26} onChoose={() => handleChoose('b')} />
        <Group gap={8} px={12} style={{ flex: 1, justifyContent: 'flex-end' }}>
          {unequalCounts && (
            <Tooltip
              label={`File A has ${fileA.count} page${fileA.count !== 1 ? 's' : ''}, File B has ${fileB.count} page${fileB.count !== 1 ? 's' : ''}. The extra ${Math.abs(fileA.count - fileB.count)} page${Math.abs(fileA.count - fileB.count) !== 1 ? 's' : ''} will be appended at the end.`}
              multiline
              w={280}
            >
              <IconAlertTriangle size={18} color="var(--mantine-color-yellow-6)" />
            </Tooltip>
          )}
          <Checkbox
            size="sm"
            label="Reverse File B"
            checked={reverseB}
            onChange={(e) => setReverseB(e.currentTarget.checked)}
          />
          <Text size="sm" c="dimmed">First page in</Text>
          <SegmentedControl
            size="xs"
            value={firstPageIn}
            onChange={(v) => setFirstPageIn(v as FirstPageIn)}
            data={[
              { label: 'File A', value: 'a' },
              { label: 'File B', value: 'b' },
            ]}
          />
          <Button size="sm" disabled={!bothLoaded} loading={merging} onClick={handleMerge}>
            Merge & Save
          </Button>
        </Group>
      </Box>

      <Box style={{ flex: 1, overflow: 'hidden', display: 'flex' }}>
        <MergeModeThumbnailPanel
          fileA={fileA}
          fileB={fileB}
          selectedPage={selectedPage}
          onSelectPage={(file, page) => setSelectedPage({ file, page })}
          firstPageIn={firstPageIn}
          totalWidth={totalWidth}
          onWidthChange={setTotalWidth}
          colWidth={colWidth}
          reverseB={reverseB}
        />
        {selectedPath && (
          <DetailPanel
            pdfPath={selectedPath}
            pageNum={selectedPage.page}
            pageCount={selectedCount}
            rotation={selectedFile.rotations.get(selectedPage.page) ?? 0}
            onNavigate={(page) => setSelectedPage({ file: selectedPage.file, page })}
            onToggleSkip={() => selectedFile.toggleSkip(selectedPage.page)}
            onRotate={() => selectedFile.rotate(selectedPage.page)}
          />
        )}
      </Box>
    </Box>
  )
}

function FilePickerColumn({
  label, path, width, onChoose,
}: {
  label: string
  path: string | null
  width: number
  onChoose: () => void
}) {
  return (
    <Box
      style={{
        width,
        flexShrink: 0,
        padding: '6px 8px',
        borderRight: '1px solid var(--mantine-color-gray-3)',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        gap: 2,
      }}
    >
      <Group justify="space-between" gap={4} wrap="nowrap">
        <Text size="xs" c="dimmed">{label}</Text>
        <Button size="xs" variant="default" onClick={onChoose}>Choose…</Button>
      </Group>
      <Text
        size="xs"
        style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}
        title={path ?? undefined}
      >
        {path ? basename(path) : '—'}
      </Text>
    </Box>
  )
}

import { useEffect, useState } from 'react'
import { RenderPage } from '../../wailsjs/go/main/App'

interface Entry { src: string; width: number }

const entries = new Map<string, Entry>()
const loading = new Set<string>()
const failed = new Set<string>()
const listeners = new Set<() => void>()

const pk = (path: string, page: number) => `${path}\0${page}`

function notify() {
  for (const fn of listeners) fn()
}

export function subscribe(fn: () => void): () => void {
  listeners.add(fn)
  return () => listeners.delete(fn)
}

export function usePageCacheRender() {
  const [, setTick] = useState(0)
  useEffect(() => subscribe(() => setTick(t => t + 1)), [])
}

export function getSrc(path: string, page: number): string | undefined {
  return entries.get(pk(path, page))?.src
}

export function getCachedWidth(path: string, page: number): number | undefined {
  return entries.get(pk(path, page))?.width
}

export function isLoading(path: string, page: number): boolean {
  return loading.has(pk(path, page))
}

export function isFailed(path: string, page: number): boolean {
  return failed.has(pk(path, page))
}

export function load(path: string, page: number, width: number): void {
  if (!path) return
  const k = pk(path, page)
  const existing = entries.get(k)
  if (existing && existing.width >= width) return
  if (loading.has(k)) return
  if (failed.has(k)) return
  loading.add(k)
  RenderPage(path, page, Math.round(width * window.devicePixelRatio))
    .then((b64) => {
      entries.set(k, { src: `data:image/png;base64,${b64}`, width })
      loading.delete(k)
      notify()
    })
    .catch((err) => {
      loading.delete(k)
      failed.add(k)
      notify()
    })
}

export function evict(path: string): void {
  const prefix = path + '\0'
  for (const k of [...entries.keys()]) if (k.startsWith(prefix)) entries.delete(k)
  for (const k of [...failed]) if (k.startsWith(prefix)) failed.delete(k)
  notify()
}

import { useRef, useEffect } from 'react'
import { TransformWrapper, TransformComponent, ReactZoomPanPinchRef } from 'react-zoom-pan-pinch'
import { Center, Loader } from '@mantine/core'
import * as pageCache from '../hooks/pageCache'

const DETAIL_WIDTH = 1400

interface Props {
  pdfPath: string
  pageNum: number
  pageCount: number
  rotation?: number
  onNavigate: (page: number) => void
  onToggleSkip?: () => void
  onRotate?: () => void
}

export default function DetailPanel({ pdfPath, pageNum, pageCount, rotation = 0, onNavigate, onToggleSkip, onRotate }: Props) {
  pageCache.usePageCacheRender()
  const transformRef = useRef<ReactZoomPanPinchRef>(null)

  useEffect(() => {
    pageCache.load(pdfPath, pageNum, DETAIL_WIDTH)
  }, [pdfPath, pageNum])

  useEffect(() => {
    transformRef.current?.resetTransform()
  }, [pageNum, rotation])

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return
      if (e.key === 'ArrowLeft') {
        e.preventDefault()
        if (pageNum > 1) onNavigate(pageNum - 1)
      } else if (e.key === 'ArrowRight') {
        e.preventDefault()
        if (pageNum < pageCount) onNavigate(pageNum + 1)
      } else if (e.key === 'Delete' || e.key === 'Backspace') {
        e.preventDefault()
        onToggleSkip?.()
      } else if (e.key === 'r') {
        e.preventDefault()
        onRotate?.()
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [pageNum, pageCount, onNavigate, onToggleSkip, onRotate])

  const cachedWidth = pageCache.getCachedWidth(pdfPath, pageNum)
  const src = cachedWidth !== undefined && cachedWidth >= DETAIL_WIDTH
    ? pageCache.getSrc(pdfPath, pageNum)
    : undefined

  return (
    <div
      style={{
        flex: 1,
        height: '100%',
        overflow: 'hidden',
        position: 'relative',
        background: 'var(--mantine-color-gray-1)',
        padding: 8,
      }}
    >
      {pageCache.isLoading(pdfPath, pageNum) && (
        <Center style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
          <Loader />
        </Center>
      )}
      {src && (
        <TransformWrapper ref={transformRef} centerOnInit minScale={0.1} maxScale={8}>
          <TransformComponent
            wrapperStyle={{ width: '100%', height: '100%' }}
            contentStyle={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <img
              src={src}
              alt={`Page ${pageNum}`}
              draggable={false}
              style={{ maxWidth: '100%', maxHeight: '100%', display: 'block', userSelect: 'none', transform: rotation ? `rotate(${rotation}deg)` : undefined }}
            />
          </TransformComponent>
        </TransformWrapper>
      )}
    </div>
  )
}

import { useRef, useState, useEffect, forwardRef, useImperativeHandle } from 'react'
import { useVirtualizer } from '@tanstack/react-virtual'
import { Loader } from '@mantine/core'
import * as pageCache from '../../hooks/pageCache'
import { DEFAULT_WIDTH, DRAG_HANDLE_WIDTH, ITEM_PADDING, PAGE_ASPECT, LABEL_HEIGHT } from '../../constants'

const MIN_WIDTH = 120
const MAX_WIDTH = 480

const STRIP_LABEL_HEIGHT = 28

export interface ThumbnailPanelHandle {
  scrollTo: (top: number) => void
}

interface Props {
  pdfPath: string
  pageCount: number
  selectedPage: number   // 1-indexed
  onSelectPage: (page: number) => void
  label?: string
  width?: number
  hideDragHandle?: boolean
  onWidthChange?: (width: number) => void
  onScroll?: (scrollTop: number) => void
  hideScrollbar?: boolean
  topPadding?: number
  bottomPadding?: number
  pageNumberLabel?: (index: number) => number
}

const ThumbnailPanel = forwardRef<ThumbnailPanelHandle, Props>(function ThumbnailPanel(
  { pdfPath, pageCount, selectedPage, onSelectPage, label, width: controlledWidth, hideDragHandle, onWidthChange, onScroll, hideScrollbar, topPadding = 0, bottomPadding = 0, pageNumberLabel },
  ref,
) {
  const [internalWidth, setInternalWidth] = useState(DEFAULT_WIDTH)
  const panelWidth = controlledWidth ?? internalWidth

  const thumbWidth = panelWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  const itemHeight = thumbHeight + LABEL_HEIGHT + ITEM_PADDING

  const scrollRef = useRef<HTMLDivElement>(null)

  const virtualizer = useVirtualizer({
    count: pageCount,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => itemHeight,
    overscan: 3,
    paddingStart: topPadding,
  })

  // Re-estimate row heights when panel is resized
  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [itemHeight])

  const virtualItems = virtualizer.getVirtualItems()
  pageCache.usePageCacheRender()

  useEffect(() => {
    for (const item of virtualItems) pageCache.load(pdfPath, item.index + 1, thumbWidth)
  })

  // Scroll selected page into view (e.g. after keyboard navigation)
  useEffect(() => {
    virtualizer.scrollToIndex(selectedPage - 1, { align: 'auto' })
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  useImperativeHandle(ref, () => ({
    scrollTo: (top) => { if (scrollRef.current) scrollRef.current.scrollTop = top },
  }))

  useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return
      if (e.key === 'ArrowLeft') {
        e.preventDefault()
        if (selectedPage > 1) onSelectPage(selectedPage - 1)
      } else if (e.key === 'ArrowRight') {
        e.preventDefault()
        if (selectedPage < pageCount) onSelectPage(selectedPage + 1)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [selectedPage, pageCount, onSelectPage])

  const startDrag = (e: React.MouseEvent) => {
    const startX = e.clientX
    const startWidth = panelWidth
    const clamp = (w: number) => Math.max(MIN_WIDTH, Math.min(MAX_WIDTH, w))

    const onMove = (ev: MouseEvent) => {
      const w = clamp(startWidth + ev.clientX - startX)
      setInternalWidth(w)
      onWidthChange?.(w)
    }
    const onUp = (ev: MouseEvent) => {
      const w = clamp(startWidth + ev.clientX - startX)
      setInternalWidth(w)
      onWidthChange?.(w)
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
    e.preventDefault()
  }

  return (
    <div style={{ display: 'flex', height: '100%', flexShrink: 0 }}>
      <div style={{ display: 'flex', flexDirection: 'column', width: panelWidth, height: '100%' }}>
        {label && (
          <div
            style={{
              height: STRIP_LABEL_HEIGHT,
              flexShrink: 0,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontSize: 11,
              fontWeight: 600,
              color: 'var(--mantine-color-dimmed)',
              borderBottom: '1px solid var(--mantine-color-gray-2)',
            }}
          >
            {label}
          </div>
        )}
        <div
          ref={scrollRef}
          onScroll={(e) => onScroll?.(e.currentTarget.scrollTop)}
          className={hideScrollbar ? 'hide-scrollbar' : undefined}
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            overflowX: 'hidden',
            background: 'var(--mantine-color-gray-3)',
          }}
        >
          <div style={{ height: virtualizer.getTotalSize() + bottomPadding, position: 'relative' }}>
            {virtualizer.getVirtualItems().map(item => {
              const page = item.index + 1
              const src = pageCache.getSrc(pdfPath, page)
              const isSelected = page === selectedPage

              return (
                <div
                  key={item.key}
                  style={{
                    position: 'absolute',
                    top: item.start,
                    left: 0,
                    width: '100%',
                    height: item.size,
                    padding: ITEM_PADDING,
                    paddingBottom: 0,
                    boxSizing: 'border-box',
                    cursor: 'pointer',
                  }}
                  onClick={() => onSelectPage(page)}
                >
                  <div
                    style={{
                      border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
                      borderRadius: 4,
                      overflow: 'hidden',
                      background: 'var(--mantine-color-gray-1)',
                    }}
                  >
                    {src ? (
                      <img
                        src={src}
                        alt={`Page ${page}`}
                        style={{ width: '100%', display: 'block' }}
                        draggable={false}
                      />
                    ) : (
                      <div
                        style={{
                          width: '100%',
                          height: thumbHeight,
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                        }}
                      >
                        {pageCache.isLoading(pdfPath, page) && <Loader size="xs" />}
                      </div>
                    )}
                  </div>
                  <div
                    style={{
                      textAlign: 'center',
                      fontSize: 11,
                      color: 'var(--mantine-color-gray-7)',
                      height: LABEL_HEIGHT,
                      lineHeight: `${LABEL_HEIGHT}px`,
                    }}
                  >
                    {pageNumberLabel ? pageNumberLabel(item.index) : page}
                  </div>
                </div>
              )
            })}
          </div>
        </div>
      </div>

      {/* Resize drag handle */}
      {!hideDragHandle && (
        <div
          onMouseDown={startDrag}
          style={{
            width: DRAG_HANDLE_WIDTH,
            height: '100%',
            cursor: 'col-resize',
            flexShrink: 0,
            background: 'var(--mantine-color-gray-3)',
          }}
        />
      )}
    </div>
  )
})

export default ThumbnailPanel

import { useRef, useEffect, useState } from 'react'
import { useVirtualizer } from '@tanstack/react-virtual'
import { Box, Loader } from '@mantine/core'
import { IconX, IconRotateClockwise } from '@tabler/icons-react'
import * as pageCache from '../../hooks/pageCache'
import { PDFFile } from '../../hooks/usePDFFile'
import { DEFAULT_WIDTH, DRAG_HANDLE_WIDTH, ITEM_PADDING, LABEL_HEIGHT, PAGE_ASPECT } from '../../constants'

const MIN_TOTAL_WIDTH = 240
const MAX_TOTAL_WIDTH = 960
export const DEFAULT_TOTAL_WIDTH = DEFAULT_WIDTH * 2

export type FirstPageIn = 'a' | 'b'
export type SelectedPage = { file: FirstPageIn, page: number }

interface Props {
  fileA: PDFFile
  fileB: PDFFile
  selectedPage: SelectedPage
  onSelectPage: (file: FirstPageIn, page: number) => void
  firstPageIn: FirstPageIn
  totalWidth: number
  onWidthChange: (w: number) => void
  colWidth: number
  reverseB: boolean
}

function makePageNumberLabel(isFirst: boolean, countOther: number) {
  return (index: number) => {
    const n = index + 1
    if (n <= countOther) return isFirst ? 2 * n - 1 : 2 * n
    return 2 * countOther + (n - countOther)
  }
}

export default function MergeModeThumbnailPanel({
  fileA, fileB,
  selectedPage, onSelectPage,
  firstPageIn, totalWidth, onWidthChange, colWidth, reverseB,
}: Props) {
  const selectedPageA = selectedPage.file === 'a' ? selectedPage.page : null
  const selectedPageB = selectedPage.file === 'b' ? selectedPage.page : null
  const thumbWidth = colWidth - ITEM_PADDING * 2
  const thumbHeight = Math.round(thumbWidth * PAGE_ASPECT)
  const itemHeight = thumbHeight + LABEL_HEIGHT + ITEM_PADDING

  const bothLoaded = fileA.path !== null && fileB.path !== null
  const halfThumbHeight = Math.round(thumbHeight / 2)
  const offsetA = bothLoaded && firstPageIn === 'b' ? halfThumbHeight : 0
  const offsetB = bothLoaded && firstPageIn === 'a' ? halfThumbHeight : 0

  const totalHeight = Math.max(offsetA + fileA.count * itemHeight, offsetB + fileB.count * itemHeight, 0)

  const scrollRef = useRef<HTMLDivElement>(null)

  pageCache.usePageCacheRender()

  const aIsFirst = firstPageIn === 'a'
  const pageLabelA = bothLoaded ? makePageNumberLabel(aIsFirst, aIsFirst ? fileB.count : fileA.count) : undefined
  const pageLabelB = bothLoaded ? makePageNumberLabel(!aIsFirst, aIsFirst ? fileA.count : fileB.count) : undefined

  const startDrag = (e: React.MouseEvent) => {
    const startX = e.clientX
    const startWidth = totalWidth
    const clamp = (w: number) => Math.max(MIN_TOTAL_WIDTH, Math.min(MAX_TOTAL_WIDTH, w))

    const onMove = (ev: MouseEvent) => onWidthChange(clamp(startWidth + ev.clientX - startX))
    const onUp = (ev: MouseEvent) => {
      onWidthChange(clamp(startWidth + ev.clientX - startX))
      document.removeEventListener('mousemove', onMove)
      document.removeEventListener('mouseup', onUp)
    }
    document.addEventListener('mousemove', onMove)
    document.addEventListener('mouseup', onUp)
    e.preventDefault()
  }

  return (
    <Box style={{ display: 'flex', height: '100%', flexShrink: 0 }}>
      <Box style={{ display: 'flex', flexDirection: 'column', width: totalWidth, height: '100%' }}>
        {/* Single scroll area with two absolute columns */}
        <div
          ref={scrollRef}
          style={{
            flex: 1,
            minHeight: 0,
            overflowY: 'auto',
            overflowX: 'hidden',
            background: 'var(--mantine-color-gray-3)',
          }}
        >
          <div style={{ height: totalHeight, position: 'relative' }}>
            <div style={{ position: 'absolute', left: 0, top: 0, width: colWidth, height: '100%' }}>
              <ThumbColumn
                scrollRef={scrollRef}
                file={fileA}
                pdfPath={fileA.path ?? ''}
                itemHeight={itemHeight}
                paddingStart={offsetA}
                thumbWidth={thumbWidth}
                thumbHeight={thumbHeight}
                selectedPage={selectedPageA}
                onSelectPage={(page) => onSelectPage('a', page)}
                pageLabel={pageLabelA}
              />
            </div>
            <div style={{ position: 'absolute', left: colWidth, top: 0, width: colWidth, height: '100%' }}>
              <ThumbColumn
                scrollRef={scrollRef}
                file={fileB}
                pdfPath={fileB.path ?? ''}
                itemHeight={itemHeight}
                paddingStart={offsetB}
                thumbWidth={thumbWidth}
                thumbHeight={thumbHeight}
                selectedPage={selectedPageB}
                onSelectPage={(page) => onSelectPage('b', page)}
                pageLabel={pageLabelB}
                reverse={reverseB}
              />
            </div>
          </div>
        </div>
      </Box>

      {/* Resize drag handle */}
      <div
        onMouseDown={startDrag}
        style={{
          width: DRAG_HANDLE_WIDTH,
          height: '100%',
          cursor: 'col-resize',
          flexShrink: 0,
          background: 'var(--mantine-color-gray-3)',
        }}
      />
    </Box>
  )
}

interface ThumbColumnProps {
  scrollRef: React.RefObject<HTMLDivElement | null>
  file: PDFFile
  pdfPath: string
  itemHeight: number
  paddingStart: number
  thumbWidth: number
  thumbHeight: number
  selectedPage: number | null
  onSelectPage: (page: number) => void
  pageLabel?: (index: number) => number
  reverse?: boolean
}

function ThumbColumn({
  scrollRef, file, pdfPath, itemHeight, paddingStart,
  thumbWidth, thumbHeight,
  selectedPage, onSelectPage, pageLabel,
  reverse,
}: ThumbColumnProps) {
  const { count, skipped, rotations, toggleSkip, rotate } = file
  const pageAt = (index: number) => reverse ? count - index : index + 1
  const [hoveredPage, setHoveredPage] = useState<number | null>(null)
  const virtualizer = useVirtualizer({
    count,
    getScrollElement: () => scrollRef.current,
    estimateSize: () => itemHeight,
    overscan: 3,
    paddingStart,
  })

  useEffect(() => {
    virtualizer.measure()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [itemHeight])

  useEffect(() => {
    for (const item of virtualizer.getVirtualItems()) pageCache.load(pdfPath, pageAt(item.index), thumbWidth)
  })

  useEffect(() => {
    if (selectedPage !== null && count > 0) {
      const displayIndex = reverse ? count - selectedPage : selectedPage - 1
      virtualizer.scrollToIndex(displayIndex, { align: 'auto' })
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedPage])

  return virtualizer.getVirtualItems().map(item => {
    const page = pageAt(item.index)
    const src = pageCache.getSrc(pdfPath, page)
    const isSelected = page === selectedPage
    const isSkipped = skipped.has(page)
    const showSkipBtn = hoveredPage === page || isSkipped
    const rotation = rotations.get(page) ?? 0
    const isRotated = rotation !== 0
    const showRotateBtn = hoveredPage === page || isRotated
    const isOddRotation = rotation === 90 || rotation === 270
    const imgTransform = rotation ? `rotate(${rotation}deg)${isOddRotation ? ` scale(${210 / 297})` : ''}` : undefined
    return (
      <div
        key={item.key}
        onClick={() => onSelectPage(page)}
        onMouseEnter={() => setHoveredPage(page)}
        onMouseLeave={() => setHoveredPage(null)}
        style={{
          position: 'absolute',
          top: item.start,
          left: 0,
          width: '100%',
          height: item.size,
          padding: ITEM_PADDING,
          paddingBottom: 0,
          boxSizing: 'border-box',
          cursor: 'pointer',
        }}
      >
        <div style={{
          position: 'relative',
          border: `2px solid ${isSelected ? 'var(--mantine-color-blue-5)' : 'transparent'}`,
          borderRadius: 4,
        }}>
          <div style={{ overflow: 'hidden', borderRadius: 2, background: 'var(--mantine-color-gray-1)' }}>
            {src ? (
              <img src={src} alt={`page ${page}`} style={{ width: '100%', display: 'block', opacity: isSkipped ? 0.3 : 1, transform: imgTransform }} draggable={false} />
            ) : (
              <div style={{ width: '100%', height: thumbHeight, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                {pageCache.isLoading(pdfPath, page) && <Loader size="xs" />}
              </div>
            )}
          </div>
          {showRotateBtn && (
            <div
              onClick={(e) => { e.stopPropagation(); rotate(page) }}
              style={{
                position: 'absolute', top: 3, left: 3,
                width: 16, height: 16, borderRadius: 3,
                background: isRotated ? 'var(--mantine-color-blue-6)' : 'rgba(0,0,0,0.45)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                cursor: 'pointer', color: 'white',
              }}
            >
              <IconRotateClockwise size={10} stroke={3} />
            </div>
          )}
          {showSkipBtn && (
            <div
              onClick={(e) => { e.stopPropagation(); toggleSkip(page) }}
              style={{
                position: 'absolute', top: 3, right: 3,
                width: 16, height: 16, borderRadius: 3,
                background: isSkipped ? 'var(--mantine-color-orange-6)' : 'rgba(0,0,0,0.45)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                cursor: 'pointer', color: 'white',
              }}
            >
              <IconX size={10} stroke={3} />
            </div>
          )}
        </div>
        <div style={{ textAlign: 'center', fontSize: 11, color: isSkipped ? 'var(--mantine-color-gray-5)' : 'var(--mantine-color-gray-7)', height: LABEL_HEIGHT, lineHeight: `${LABEL_HEIGHT}px` }}>
          {pageLabel ? pageLabel(item.index) : page}
        </div>
      </div>
    )
  })
}

